def remove_document(cls, doc, tenant_id):
    from api.db.services.task_service import TaskService, cancel_all_task_of

    if not cls.delete_document_and_update_kb_counts(doc.id):
        return True

    # Cancel all running tasks first Using preset function in task_service.py ---  set cancel flag in Redis
    try:
        cancel_all_task_of(doc.id)
        logging.info(f"Cancelled all tasks for document {doc.id}")
    except Exception as e:
        logging.warning(f"Failed to cancel tasks for document {doc.id}: {e}")

    # Delete tasks from database
    try:
        TaskService.filter_delete([Task.doc_id == doc.id])
    except Exception as e:
        logging.warning(f"Failed to delete tasks for document {doc.id}: {e}")

    # Delete chunk images (non-critical, log and continue)
    try:
        cls.delete_chunk_images(doc, tenant_id)
    except Exception as e:
        logging.warning(f"Failed to delete chunk images for document {doc.id}: {e}")

    # Delete thumbnail (non-critical, log and continue)
    try:
        if doc.thumbnail and not doc.thumbnail.startswith(IMG_BASE64_PREFIX):
            if settings.STORAGE_IMPL.obj_exist(doc.kb_id, doc.thumbnail):
                settings.STORAGE_IMPL.rm(doc.kb_id, doc.thumbnail)
    except Exception as e:
        logging.warning(f"Failed to delete thumbnail for document {doc.id}: {e}")

    # Delete chunks from doc store - this is critical, log errors
    try:
        settings.docStoreConn.delete({"doc_id": doc.id}, search.index_name(tenant_id), doc.kb_id)
    except Exception as e:
        logging.error(f"Failed to delete chunks from doc store for document {doc.id}: {e}")

    # Delete document metadata (non-critical, log and continue)
    try:
        DocMetadataService.delete_document_metadata(doc.id, doc.kb_id, tenant_id)
    except Exception as e:
        logging.warning(f"Failed to delete metadata for document {doc.id}: {e}")

    # Cleanup knowledge graph references (non-critical, log and continue)
    try:
        graph_source = settings.docStoreConn.get_fields(
            settings.docStoreConn.search(["source_id"], [], {"kb_id": doc.kb_id, "knowledge_graph_kwd": ["graph"]}, [], OrderByExpr(), 0, 1, search.index_name(tenant_id), [doc.kb_id]),
            ["source_id"],
        )
        if len(graph_source) > 0 and doc.id in list(graph_source.values())[0]["source_id"]:
            settings.docStoreConn.update(
                {"kb_id": doc.kb_id, "knowledge_graph_kwd": ["entity", "relation", "graph", "subgraph", "community_report"], "source_id": doc.id},
                {"remove": {"source_id": doc.id}},
                search.index_name(tenant_id),
                doc.kb_id,
            )
            settings.docStoreConn.update({"kb_id": doc.kb_id, "knowledge_graph_kwd": ["graph"]}, {"removed_kwd": "Y"}, search.index_name(tenant_id), doc.kb_id)
            settings.docStoreConn.delete(
                {"kb_id": doc.kb_id, "knowledge_graph_kwd": ["entity", "relation", "graph", "subgraph", "community_report"], "must_not": {"exists": "source_id"}},
                search.index_name(tenant_id),
                doc.kb_id,
            )
    except Exception as e:
        logging.warning(f"Failed to cleanup knowledge graph for document {doc.id}: {e}")

    return True

async def collect():
    global CONSUMER_NAME, DONE_TASKS, FAILED_TASKS
    global UNACKED_ITERATOR

    svr_queue_names = settings.get_svr_queue_names()
    redis_msg = None
    try:
        if not UNACKED_ITERATOR:
            UNACKED_ITERATOR = REDIS_CONN.get_unacked_iterator(svr_queue_names, SVR_CONSUMER_GROUP_NAME, CONSUMER_NAME)
        try:
            redis_msg = next(UNACKED_ITERATOR)
        except StopIteration:
            for svr_queue_name in svr_queue_names:
                redis_msg = REDIS_CONN.queue_consumer(svr_queue_name, SVR_CONSUMER_GROUP_NAME, CONSUMER_NAME)
                if redis_msg:
                    break
    except Exception as e:
        logging.exception(f"collect got exception: {e}")
        return None, None

    if not redis_msg:
        return None, None
    msg = redis_msg.get_message()
    if not msg:
        logging.error(f"collect got empty message of {redis_msg.get_msg_id()}")
        redis_msg.ack()
        return None, None

    canceled = False
    if msg.get("doc_id", "") in [GRAPH_RAPTOR_FAKE_DOC_ID, CANVAS_DEBUG_DOC_ID]:
        task = msg
        if task["task_type"] in PIPELINE_SPECIAL_PROGRESS_FREEZE_TASK_TYPES:
            task = TaskService.get_task(msg["id"], msg["doc_ids"])
            if task:
                task["doc_id"] = msg["doc_id"]
                task["doc_ids"] = msg.get("doc_ids", []) or []
    elif msg.get("task_type") == PipelineTaskType.MEMORY.lower():
        _, task_obj = TaskService.get_by_id(msg["id"])
        task = task_obj.to_dict()
    else:
        task = TaskService.get_task(msg["id"])

    if task:
        canceled = has_canceled(task["id"])
    if not task or canceled:
        state = "is unknown" if not task else "has been cancelled"
        FAILED_TASKS += 1
        logging.warning(f"collect task {msg['id']} {state}")
        redis_msg.ack()
        return None, None

    task_type = msg.get("task_type", "")
    task["task_type"] = task_type
    if task_type[:8] == "dataflow":
        task["tenant_id"] = msg["tenant_id"]
        task["dataflow_id"] = msg["dataflow_id"]
        task["kb_id"] = msg.get("kb_id", "")
    if task_type[:6] == "memory":
        task["memory_id"] = msg["memory_id"]
        task["source_id"] = msg["source_id"]
        task["message_dict"] = msg["message_dict"]
    return redis_msg, task

def queue_tasks(doc: dict, bucket: str, name: str, priority: int):
    """
    ...
    """

    def new_task():
        return {
            "id": get_uuid(),
            "doc_id": doc["id"],
            "progress": 0.0,
            "from_page": 0,
            "to_page": 100000000,
            "begin_at": datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
        }

    parse_task_array = []

    if doc["type"] == FileType.PDF.value:
        file_bin = settings.STORAGE_IMPL.get(bucket, name)
        do_layout = doc["parser_config"].get("layout_recognize", "DeepDOC")
        pages = PdfParser.total_page_number(doc["name"], file_bin)
        if pages is None:
            pages = 0
        page_size = doc["parser_config"].get("task_page_size") or 12
        if doc["parser_id"] == "paper":
            page_size = doc["parser_config"].get("task_page_size") or 22
        if doc["parser_id"] in ["one", "knowledge_graph"] or do_layout != "DeepDOC" or doc["parser_config"].get("toc_extraction", False):
            page_size = 10 ** 9
        page_ranges = doc["parser_config"].get("pages") or [(1, 10 ** 5)]
        for s, e in page_ranges:
            s -= 1
            s = max(0, s)
            e = min(e - 1, pages)
            for p in range(s, e, page_size):
                task = new_task()
                task["from_page"] = p
                task["to_page"] = min(p + page_size, e)
                parse_task_array.append(task)

    elif doc["parser_id"] == "table":
        file_bin = settings.STORAGE_IMPL.get(bucket, name)
        rn = RAGFlowExcelParser.row_number(doc["name"], file_bin)
        for i in range(0, rn, 3000):
            task = new_task()
            task["from_page"] = i
            task["to_page"] = min(i + 3000, rn)
            parse_task_array.append(task)
    else:
        parse_task_array.append(new_task())

    chunking_config = DocumentService.get_chunking_config(doc["id"])
    for task in parse_task_array:
        hasher = xxhash.xxh64()
        for field in sorted(chunking_config.keys()):
            if field == "parser_config":
                for k in ["raptor", "graphrag"]:
                    if k in chunking_config[field]:
                        del chunking_config[field][k]
            hasher.update(str(chunking_config[field]).encode("utf-8"))
        for field in ["doc_id", "from_page", "to_page"]:
            hasher.update(str(task.get(field, "")).encode("utf-8"))
        task_digest = hasher.hexdigest()
        task["digest"] = task_digest
        task["progress"] = 0.0
        task["priority"] = priority

def insert_citations(self, answer, chunks, chunk_v,
                     embd_mdl, tkweight=0.1, vtweight=0.9):
    assert len(chunks) == len(chunk_v)
    if not chunks:
        return answer, set([])
    pieces = re.split(r"(```)", answer)
    if len(pieces) >= 3:
        i = 0
        pieces_ = []
        while i < len(pieces):
            if pieces[i] == "```":
                st = i
                i += 1
                while i < len(pieces) and pieces[i] != "```":
                    i += 1
                if i < len(pieces):
                    i += 1
                pieces_.append("".join(pieces[st: i]) + "\n")
            else:
                # Sentence boundary regex includes Arabic punctuation (،  ؛ ؟ ۔)
                pieces_.extend(
                    re.split(
                        r"([^\|][；。？!！،؛؟۔\n]|[a-z\u0600-\u06FF][.?;!،؛؟][ \n])",
                        pieces[i]))
                i += 1
        pieces = pieces_
    else:
        # Sentence boundary regex includes Arabic punctuation (، ؛ ؟ ۔)
        pieces = re.split(r"([^\|][；。？!！،؛؟۔\n]|[a-z\u0600-\u06FF][.?;!،؛؟][ \n])", answer)
    for i in range(1, len(pieces)):
        if re.match(r"([^\|][；。？!！،؛؟۔\n]|[a-z\u0600-\u06FF][.?;!،؛؟][ \n])", pieces[i]):
            pieces[i - 1] += pieces[i][0]
            pieces[i] = pieces[i][1:]
    idx = []
    pieces_ = []
    for i, t in enumerate(pieces):
        if len(t) < 5:
            continue
        idx.append(i)
        pieces_.append(t)
    logging.debug("{} => {}".format(answer, pieces_))
    if not pieces_:
        return answer, set([])

    ans_v, _ = embd_mdl.encode(pieces_)
    for i in range(len(chunk_v)):
        if len(ans_v[0]) != len(chunk_v[i]):
            chunk_v[i] = [0.0] * len(ans_v[0])
            logging.warning(
                "The dimension of query and chunk do not match: {} vs. {}".format(len(ans_v[0]), len(chunk_v[i])))

    assert len(ans_v[0]) == len(chunk_v[0]), "The dimension of query and chunk do not match: {} vs. {}".format(
        len(ans_v[0]), len(chunk_v[0]))

    chunks_tks = [rag_tokenizer.tokenize(self.qryr.rmWWW(ck)).split()
                  for ck in chunks]
    cites = {}
    thr = 0.63
    while thr > 0.3 and len(cites.keys()) == 0 and pieces_ and chunks_tks:
        for i, a in enumerate(pieces_):
            sim, tksim, vtsim = self.qryr.hybrid_similarity(ans_v[i],
                                                            chunk_v,
                                                            rag_tokenizer.tokenize(
                                                                self.qryr.rmWWW(pieces_[i])).split(),
                                                            chunks_tks,
                                                            tkweight, vtweight)
            mx = np.max(sim) * 0.99
            logging.debug("{} SIM: {}".format(pieces_[i], mx))
            if mx < thr:
                continue
            cites[idx[i]] = list(
                set([str(ii) for ii in range(len(chunk_v)) if sim[ii] > mx]))[:4]
        thr *= 0.8

    res = ""
    seted = set([])
    for i, p in enumerate(pieces):
        res += p
        if i not in idx:
            continue
        if i not in cites:
            continue
        for c in cites[i]:
            assert int(c) < len(chunk_v)
        for c in cites[i]:
            if c in seted:
                continue
            res += f" [ID:{c}]"
            seted.add(c)

    return res, seted

async def _async_chat_streamly(self, history, gen_conf, **kwargs):
    logging.info("[HISTORY STREAMLY]" + json.dumps(history, ensure_ascii=False, indent=4))
    reasoning_start = False

    request_kwargs = {"model": self.model_name, "messages": history, "stream": True, **gen_conf}
    stop = kwargs.get("stop")
    if stop:
        request_kwargs["stop"] = stop

    response = await self.async_client.chat.completions.create(**request_kwargs)
    async for resp in response:
        if not resp.choices:
            continue
        if not resp.choices[0].delta.content:
            resp.choices[0].delta.content = ""
        _reasoning = getattr(resp.choices[0].delta, "reasoning_content", None) or getattr(resp.choices[0].delta, "reasoning", None)
        if kwargs.get("with_reasoning", True) and _reasoning:
            ans = ""
            if not reasoning_start:
                reasoning_start = True
                ans = "<think>"
            ans += _reasoning + "</think>"
        else:
            reasoning_start = False
            ans = resp.choices[0].delta.content
        tol = total_token_count_from_response(resp)
        if not tol:
            tol = num_tokens_from_string(resp.choices[0].delta.content)

        finish_reason = resp.choices[0].finish_reason if hasattr(resp.choices[0], "finish_reason") else ""
        if finish_reason == "length":
            if is_chinese(ans):
                ans += LENGTH_NOTIFICATION_CN
            else:
                ans += LENGTH_NOTIFICATION_EN
        yield ans, tol

