@DB.connection_context()
def model_instance(cls, model_config: dict, lang="Chinese", **kwargs):
    if not model_config:
        raise LookupError("Model config is required")
    kwargs.update({"provider": model_config["llm_factory"]})
    if model_config["model_type"] == LLMType.EMBEDDING.value:
        if model_config["llm_factory"] not in EmbeddingModel:
            return None
        return EmbeddingModel[model_config["llm_factory"]](model_config["api_key"], model_config["llm_name"], base_url=model_config["api_base"])

    elif model_config["model_type"] == LLMType.RERANK:
        if model_config["llm_factory"] not in RerankModel:
            return None
        return RerankModel[model_config["llm_factory"]](model_config["api_key"], model_config["llm_name"], base_url=model_config["api_base"])

    elif model_config["model_type"] == LLMType.IMAGE2TEXT.value:
        if model_config["llm_factory"] not in CvModel:
            return None
        return CvModel[model_config["llm_factory"]](model_config["api_key"], model_config["llm_name"], lang, base_url=model_config["api_base"], **kwargs)

    elif model_config["model_type"] == LLMType.CHAT.value:
        if model_config["llm_factory"] not in ChatModel:
            return None
        return ChatModel[model_config["llm_factory"]](model_config["api_key"], model_config["llm_name"], base_url=model_config["api_base"], **kwargs)

    elif model_config["model_type"] == LLMType.SPEECH2TEXT:
        if model_config["llm_factory"] not in Seq2txtModel:
            return None
        return Seq2txtModel[model_config["llm_factory"]](key=model_config["api_key"], model_name=model_config["llm_name"], lang=lang, base_url=model_config["api_base"])
    elif model_config["model_type"] == LLMType.TTS:
        if model_config["llm_factory"] not in TTSModel:
            return None
        return TTSModel[model_config["llm_factory"]](model_config["api_key"], model_config["llm_name"], base_url=model_config["api_base"],
        )

    elif model_config["model_type"] == LLMType.OCR:
        if model_config["llm_factory"] not in OcrModel:
            return None
        return OcrModel[model_config["llm_factory"]](key=model_config["api_key"], model_name=model_config["llm_name"], base_url=model_config.get("api_base", ""), **kwargs,
        )

    return None

@classmethod
@DB.connection_context()
def is_parsed_done(cls, kb_id):
    from common.constants import TaskStatus
    from api.db.services.document_service import DocumentService

    # Get dataset information
    kbs = cls.query(id=kb_id)
    if not kbs:
        return False, "Knowledge base not found"
    kb = kbs[0]

    # Get all documents in the dataset
    docs, _ = DocumentService.get_by_kb_id(kb_id, 1, 1000, "create_time", True, "", [], [])

    # Check parsing status of each document
    for doc in docs:
        # If document is being parsed, don't allow chat creation
        if doc['run'] == TaskStatus.RUNNING.value or doc['run'] == TaskStatus.CANCEL.value or doc['run'] == TaskStatus.FAIL.value:
            return False, f"Document '{doc['name']}' in dataset '{kb.name}' is still being parsed. Please wait until all documents are parsed before starting a chat."
        # If document is not yet parsed and has no chunks, don't allow chat creation
        if doc['run'] == TaskStatus.UNSTART.value and doc['chunk_num'] == 0:
            return False, f"Document '{doc['name']}' in dataset '{kb.name}' has not been parsed yet. Please parse all documents before starting a chat."

    return True, None

@timeout(60 * 20)
def _chat(self, system, history, gen_conf={}, task_id=""):
    hist = deepcopy(history)
    conf = deepcopy(gen_conf)
    response = get_llm_cache(self._llm.llm_name, system, hist, conf)
    if response:
        return response
    _, system_msg = message_fit_in([{"role": "system", "content": system}], int(self._llm.max_length * 0.92))
    response = ""
    for attempt in range(3):
        if task_id:
            if has_canceled(task_id):
                logging.info(f"Task {task_id} cancelled during entity resolution candidate processing.")
                raise TaskCanceledException(f"Task {task_id} was cancelled")
        try:
            response = asyncio.run(self._llm.async_chat(system_msg[0]["content"], hist, conf))
            response = re.sub(r"^.*</think>", "", response[0], flags=re.DOTALL)
            if response.find("**ERROR**") >= 0:
                raise Exception(response)
            set_llm_cache(self._llm.llm_name, system, response, history, gen_conf)
            break
        except Exception as e:
            logging.exception(e)
            if attempt == 2:
                raise

    return response

def get_variable_value(self, exp: str) -> Any:
    exp = exp.strip("{").strip("}").strip(" ").strip("{").strip("}")
    if exp.find("@") < 0:
        return self.globals[exp]
    cpn_id, var_nm = exp.split("@")
    cpn = self.get_component(cpn_id)
    if not cpn:
        raise Exception(f"Can't find variable: '{cpn_id}@{var_nm}'")
    parts = var_nm.split(".", 1)
    root_key = parts[0]
    rest = parts[1] if len(parts) > 1 else ""
    root_val = cpn["obj"].output(root_key)

    if not rest:
        return root_val
    return self.get_variable_param_value(root_val,rest)

def get_variable_param_value(self, obj: Any, path: str) -> Any:
    cur = obj
    if not path:
        return cur
    for key in path.split('.'):
        if cur is None:
            return None

        if isinstance(cur, str):
            try:
                cur = json.loads(cur)
            except Exception:
                return None

        if isinstance(cur, dict):
            cur = cur.get(key)
            continue

        if isinstance(cur, (list, tuple)):
            try:
                idx = int(key)
                cur = cur[idx]
            except Exception:
                return None
            continue

        cur = getattr(cur, key, None)
    return cur

async def invoke_async(self, **kwargs) -> dict[str, Any]:
    """
    Async wrapper for component invocation.
    Prefers coroutine `_invoke_async` if present; otherwise falls back to `_invoke`.
    Handles timing and error recording consistently with `invoke`.
    """
    self.set_output("_created_time", time.perf_counter())
    try:
        if self.check_if_canceled("Component processing"):
            return

        fn_async = getattr(self, "_invoke_async", None)
        if fn_async and asyncio.iscoroutinefunction(fn_async):
            await fn_async(**kwargs)
        elif asyncio.iscoroutinefunction(self._invoke):
            await self._invoke(**kwargs)
        else:
            await thread_pool_exec(self._invoke, **kwargs)
    except Exception as e:
        if self.get_exception_default_value():
            self.set_exception_default_value()
        else:
            self.set_output("_ERROR", str(e))
        logging.exception(e)
    self._param.debug_inputs = {}
    self.set_output("_elapsed_time", time.perf_counter() - self.output("_created_time"))
    return self.output()

def _sys_prompt_and_msg(self, msg, args):
    if isinstance(self._param.prompts, str):
        self._param.prompts = [{"role": "user", "content": self._param.prompts}]
    for p in self._param.prompts:
        if msg and msg[-1]["role"] == p["role"]:
            continue
        p = deepcopy(p)
        p["content"] = self.string_format(p["content"], args)
        msg.append(p)
    return msg, self.string_format(self._param.sys_prompt, args)

@staticmethod
def _extract_data_images(value) -> list[str]:
    imgs = []

    def walk(v):
        if v is None:
            return
        if isinstance(v, str):
            v = v.strip()
            if v.startswith("data:image/"):
                imgs.append(v)
            return
        if isinstance(v, (list, tuple, set)):
            for item in v:
                walk(item)
            return
        if isinstance(v, dict):
            if "content" in v:
                walk(v.get("content"))
            else:
                for item in v.values():
                    walk(item)

    walk(value)
    return imgs

def encode(self, texts: list):
    if self.langfuse:
        generation = self.langfuse.start_generation(trace_context=self.trace_context, name="encode", model=self.model_config["llm_name"], input={"texts": texts})

    safe_texts = []
    for text in texts:
        token_size = num_tokens_from_string(text)
        if token_size > self.max_length:
            target_len = int(self.max_length * 0.95)
            safe_texts.append(text[:target_len])
        else:
            safe_texts.append(text)

    embeddings, used_tokens = self.mdl.encode(safe_texts)
    if self.model_config["llm_factory"] == "Builtin":
        logging.info("LLMBundle.encode_queries query: {}, emd len: {}, used_tokens: {}. Builtin model don't need to update token usage".format(texts, len(embeddings), used_tokens))
    elif not TenantLLMService.increase_usage_by_id(self.model_config["id"], used_tokens):
        logging.error("LLMBundle.encode can't update token usage for <tenant redacted>/EMBEDDING used_tokens: {}".format(used_tokens))

    if self.langfuse:
        generation.update(usage_details={"total_tokens": used_tokens})
        generation.end()

    return embeddings, used_tokens

def kb_prompt(kbinfos, max_tokens, hash_id=False):
    from api.db.services.document_service import DocumentService
    from api.db.services.doc_metadata_service import DocMetadataService

    knowledges = [get_value(ck, "content", "content_with_weight") for ck in kbinfos["chunks"]]
    kwlg_len = len(knowledges)
    used_token_count = 0
    chunks_num = 0
    for i, c in enumerate(knowledges):
        if not c:
            continue
        used_token_count += num_tokens_from_string(c)
        chunks_num += 1
        if max_tokens * 0.97 < used_token_count:
            knowledges = knowledges[:i]
            logging.warning(f"Not all the retrieval into prompt: {len(knowledges)}/{kwlg_len}")
            break

    docs = DocumentService.get_by_ids([get_value(ck, "doc_id", "document_id") for ck in kbinfos["chunks"][:chunks_num]])

    docs_with_meta = {}
    for d in docs:
        meta = DocMetadataService.get_document_metadata(d.id)
        docs_with_meta[d.id] = meta if meta else {}
    docs = docs_with_meta

    def draw_node(k, line):
        if line is not None and not isinstance(line, str):
            line = str(line)
        if not line:
            return ""
        return f"\n├── {k}: " + re.sub(r"\n+", " ", line, flags=re.DOTALL)

    knowledges = []
    for i, ck in enumerate(kbinfos["chunks"][:chunks_num]):
        cnt = "\nID: {}".format(i if not hash_id else hash_str2int(get_value(ck, "id", "chunk_id"), 500))
        cnt += draw_node("Title", get_value(ck, "docnm_kwd", "document_name"))
        cnt += draw_node("URL", ck['url']) if "url" in ck else ""
        for k, v in docs.get(get_value(ck, "doc_id", "document_id"), {}).items():
            cnt += draw_node(k, v)
        cnt += "\n└── Content:\n"
        cnt += get_value(ck, "content", "content_with_weight")
        knowledges.append(cnt)

    return knowledges

async def _retrieve_information(self, search_query):
    """Retrieve information from different sources"""
    # 1. Knowledge base retrieval
    kbinfos = []
    try:
        kbinfos = await self._kb_retrieve(question=search_query) if self._kb_retrieve else {"chunks": [], "doc_aggs": []}
    except Exception as e:
        logging.error(f"Knowledge base retrieval error: {e}")

    # 2. Web retrieval (if Tavily API is configured)
    try:
        if self.prompt_config.get("tavily_api_key"):
            tav = Tavily(self.prompt_config["tavily_api_key"])
            tav_res = tav.retrieve_chunks(search_query)
            kbinfos["chunks"].extend(tav_res["chunks"])
            kbinfos["doc_aggs"].extend(tav_res["doc_aggs"])
    except Exception as e:
        logging.error(f"Web retrieval error: {e}")

    # 3. Knowledge graph retrieval (if configured)
    try:
        if self.prompt_config.get("use_kg") and self._kg_retrieve:
            ck = await self._kg_retrieve(question=search_query)
            if ck["content_with_weight"]:
                kbinfos["chunks"].insert(0, ck)
    except Exception as e:
        logging.error(f"Knowledge graph retrieval error: {e}")

    return kbinfos

def get_models(dialog):
    embd_mdl, chat_mdl, rerank_mdl, tts_mdl = None, None, None, None
    kbs = KnowledgebaseService.get_by_ids(dialog.kb_ids)
    embedding_list = list(set([kb.embd_id for kb in kbs]))
    if len(embedding_list) > 1:
        raise Exception("**ERROR**: Knowledge bases use different embedding models.")

    if embedding_list:
        embd_model_config = get_model_config_by_type_and_name(dialog.tenant_id, LLMType.EMBEDDING, embedding_list[0])
        embd_mdl = LLMBundle(dialog.tenant_id, embd_model_config)
        if not embd_mdl:
            raise LookupError("Embedding model(%s) not found" % embedding_list[0])

    if dialog.tenant_llm_id:
        chat_model_config = get_model_config_by_id(dialog.tenant_llm_id)
    elif dialog.llm_id:
        chat_model_config = get_model_config_by_type_and_name(dialog.tenant_id, LLMType.CHAT, dialog.llm_id)
    else:
        chat_model_config = get_tenant_default_model_by_type(dialog.tenant_id, LLMType.CHAT)

    chat_mdl = LLMBundle(dialog.tenant_id, chat_model_config)

    if dialog.rerank_id:
        rerank_model_config = get_model_config_by_type_and_name(dialog.tenant_id, LLMType.RERANK, dialog.rerank_id)
        rerank_mdl = LLMBundle(dialog.tenant_id, rerank_model_config)

    if dialog.prompt_config.get("tts"):
        default_tts_model_config = get_tenant_default_model_by_type(dialog.tenant_id, LLMType.TTS)
        tts_mdl = LLMBundle(dialog.tenant_id, default_tts_model_config)
    return kbs, embd_mdl, rerank_mdl, chat_mdl, tts_mdl
